  ArrowColor Black
}

' Define classes
class LoginUI {
  <<UI>>
  +login()
}

class LoginController {
  <<Controller>>
  +login(email, password)
}

class ApplicationPOT {
  <<POT>>
  +static getInstance()
  +clearCurrentSession()
}

class UserService {
  <<Service>>
  +UserService()
  +newUserSession()
}

class UserSession {
  <<Session>>
  -String email
  +UserSession()
}

class User {
  <<Entity>>
  -Integer id
  -String email
  -String password
  -Integer nif
  -String name
  +User(email, password, nif, name)
}

' Define relationships
LoginUI ..> LoginController : uses
LoginController ..> ApplicationPOT : uses
ApplicationPOT "1" --> "1" UserSession : has
UserService "1" --> "*" UserSession : creates
UserSession "1" --> "1" User : allocates

@enduml
